(async () => {
// Strict v3 env contract preflight for single-tailor webhook.
const config = {
  appUrl: String($env.APP_URL || '').trim(),
  webhookSecret: String($env.N8N_WEBHOOK_SECRET || '').trim(),
  anthropicApiKey: String($env.ANTHROPIC_API_KEY || '').trim(),
  v3MaxRetries: String($env.V3_MAX_RETRIES || '').trim(),
  v3RetryBaseMs: String($env.V3_RETRY_BASE_MS || '').trim(),
  v3RetryCapMs: String($env.V3_RETRY_CAP_MS || '').trim()
};

const required = {
  APP_URL: config.appUrl,
  N8N_WEBHOOK_SECRET: config.webhookSecret,
  ANTHROPIC_API_KEY: config.anthropicApiKey,
  V3_MAX_RETRIES: config.v3MaxRetries,
  V3_RETRY_BASE_MS: config.v3RetryBaseMs,
  V3_RETRY_CAP_MS: config.v3RetryCapMs
};

const missing = Object.entries(required)
  .filter(([_, value]) => !String(value || '').trim())
  .map(([name]) => name);

if (missing.length > 0) {
  throw new Error('MISSING_ENV_NAMES:' + missing.join(','));
}

const payload = $input.first().json || {};

return [{
  json: {
    ...payload,
    config: {
      ...config,
      v3MaxRetries: Number(config.v3MaxRetries),
      v3RetryBaseMs: Number(config.v3RetryBaseMs),
      v3RetryCapMs: Number(config.v3RetryCapMs)
    }
  }
}];
})();

(async () => {
const trigger = $input.first().json || {};
const config = trigger.config || {};
const body = trigger.body || {};
const headers = trigger.headers || {};
const runId = 'tailor_v3_' + String($execution.id || Date.now());

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function parseJsonObject(text) {
  const raw = String(text || '');
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start < 0 || end <= start) return null;
  try {
    return JSON.parse(raw.slice(start, end + 1));
  } catch {
    return null;
  }
}

function retryAfterMs(headersObj) {
  const raw = headersObj && typeof headersObj.get === 'function' ? String(headersObj.get('retry-after') || '').trim() : '';
  if (!raw) return null;
  const n = Number(raw);
  if (Number.isFinite(n) && n >= 0) return Math.floor(n * 1000);
  const ts = Date.parse(raw);
  if (Number.isNaN(ts)) return null;
  const d = ts - Date.now();
  return d > 0 ? d : 0;
}

function shouldRetry(status) {
  if (status === 429 || status === 529) return true;
  return status >= 500 && status <= 599;
}

async function withRetry(fn, meta) {
  const maxRetries = Math.max(0, Number(config.v3MaxRetries || 0));
  const base = Math.max(1, Number(config.v3RetryBaseMs || 250));
  const cap = Math.max(base, Number(config.v3RetryCapMs || 5000));
  let attempt = 0;
  let repeated429 = false;

  while (attempt <= maxRetries) {
    attempt += 1;
    try {
      const value = await fn();
      return { value, repeated429, attempts: attempt };
    } catch (error) {
      const status = Number(error && error.status ? error.status : 0);
      if (status === 429) repeated429 = true;
      const retriable = shouldRetry(status);
      if (!retriable || attempt > maxRetries) {
        const reason = retriable
          ? 'MAX_RETRIES_REACHED_' + String(status || 'NETWORK')
          : 'NON_RETRIABLE_' + String(status || 'NETWORK');
        const wrapped = new Error(reason);
        wrapped.status = status;
        wrapped.repeated429 = repeated429;
        wrapped.stage = meta && meta.stage ? meta.stage : 'unknown';
        wrapped.userId = meta && meta.userId ? meta.userId : null;
        throw wrapped;
      }
      const retryAfter = Number(error && error.retryAfterMs ? error.retryAfterMs : 0) || 0;
      const exp = Math.min(cap, base * Math.pow(2, attempt - 1));
      const jitter = Math.floor(Math.random() * Math.max(50, Math.floor(base / 2)));
      await sleep(Math.max(retryAfter, exp + jitter));
    }
  }

  throw new Error('MAX_RETRIES_EXITED_UNEXPECTEDLY');
}

async function anthropic(payload, meta) {
  return withRetry(async () => {
    const resp = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': config.anthropicApiKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify(payload)
    });
    if (!resp.ok) {
      const err = new Error('ANTHROPIC_FAILED');
      err.status = resp.status;
      err.retryAfterMs = retryAfterMs(resp.headers);
      throw err;
    }
    return resp.json();
  }, meta);
}

async function appWebhook(type, data, extraHeaders = {}, meta = {}) {
  const url = String(config.appUrl || '').replace(/\/$/, '') + '/api/webhooks/n8n';
  return withRetry(async () => {
    const resp = await fetch(url, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': config.webhookSecret,
        'x-run-id': runId,
        ...extraHeaders
      },
      body: JSON.stringify({ type, runId, data })
    });
    if (!resp.ok) {
      const err = new Error('APP_WEBHOOK_' + type + '_FAILED');
      err.status = resp.status;
      err.retryAfterMs = retryAfterMs(resp.headers);
      throw err;
    }
    try {
      return await resp.json();
    } catch {
      return {};
    }
  }, meta);
}

async function emitWorkflowError(stage, reasonCode, payload, userId) {
  const url = String(config.appUrl || '').replace(/\/$/, '') + '/api/webhooks/n8n';
  await fetch(url, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'x-webhook-secret': config.webhookSecret,
      'x-run-id': runId
    },
    body: JSON.stringify({
      type: 'workflow_error',
      runId,
      data: {
        workflowId: 'single-job-tailoring-v3',
        nodeName: stage,
        errorType: reasonCode,
        message: stage + ':' + reasonCode,
        payload,
        userId: userId || undefined
      }
    })
  }).catch(() => null);
}

const incomingSecret = String(headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();
if (!incomingSecret || incomingSecret !== String(config.webhookSecret || '').trim()) {
  return [{ json: { ok: false, status: 401, error: 'unauthorized' } }];
}

const userId = String(body.userId || '').trim();
const jobId = String(body.jobId || '').trim();
const jobDescription = String(body.jobDescription || '').trim();
const masterCvText = String(body.masterCvText || '').trim();
const jobTitle = String(body.jobTitle || '').trim();
const company = String(body.company || '').trim();
const additionalContext = String(body.additionalContext || '').trim();

if (!userId || !jobId || !jobDescription || !masterCvText) {
  return [{
    json: {
      ok: false,
      status: 400,
      error: 'invalid_payload',
      missing: [
        !userId ? 'userId' : null,
        !jobId ? 'jobId' : null,
        !jobDescription ? 'jobDescription' : null,
        !masterCvText ? 'masterCvText' : null
      ].filter(Boolean)
    }
  }];
}

try {
  const scoringPrompt = [
    'Return ONLY JSON:',
    '{"compatibility_score":0-100,"ats_keywords":[],"matching_strengths":[],"gaps":[],"recommendation":"apply|stretch|skip"}',
    'Job description:',
    jobDescription.slice(0, 4000),
    'Candidate CV:',
    masterCvText.slice(0, 7000),
    additionalContext ? ('Additional confirmed candidate context:\\n' + additionalContext.slice(0, 2500)) : ''
  ].join('\\n');

  let score = null;
  const scoringPrimary = await anthropic({
    model: 'claude-3-5-haiku-20241022',
    max_tokens: 900,
    temperature: 0,
    messages: [{ role: 'user', content: scoringPrompt }]
  }, { stage: 'score_primary', userId });
  const scoringPrimaryText = scoringPrimary && scoringPrimary.content && scoringPrimary.content[0] ? scoringPrimary.content[0].text || '' : '';
  score = parseJsonObject(scoringPrimaryText);

  if (!score || typeof score !== 'object') {
    const scoringFallback = await anthropic({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1300,
      temperature: 0,
      messages: [{ role: 'user', content: scoringPrompt }]
    }, { stage: 'score_fallback_parse', userId });
    const scoringFallbackText = scoringFallback && scoringFallback.content && scoringFallback.content[0] ? scoringFallback.content[0].text || '' : '';
    score = parseJsonObject(scoringFallbackText);
  }

  if (!score || typeof score !== 'object') {
    throw new Error('SCORING_PARSE_FAILURE');
  }

  const atsKeywords = Array.isArray(score.ats_keywords) ? score.ats_keywords.slice(0, 12) : [];

  const tailorPrompt = [
    'Return ONLY JSON:',
    '{"tailored_cv_markdown":"...","motivation_letter_markdown":"..."}',
    'Never fabricate facts. Use only candidate-provided information.',
    'ATS keywords:',
    JSON.stringify(atsKeywords),
    'Job title:',
    jobTitle || 'Untitled Position',
    'Company:',
    company || 'Unknown Company',
    'Job description:',
    jobDescription.slice(0, 4000),
    'Candidate CV:',
    masterCvText.slice(0, 7000),
    additionalContext ? ('Additional confirmed candidate context:\\n' + additionalContext.slice(0, 2500)) : ''
  ].join('\\n');

  let tailorResponse = null;
  let repeated429 = false;
  try {
    tailorResponse = await anthropic({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 2600,
      temperature: 0.1,
      messages: [{ role: 'user', content: tailorPrompt }]
    }, { stage: 'tailor_primary', userId });
  } catch (error) {
    repeated429 = Boolean(error && error.repeated429);
    if (!repeated429) throw error;
  }

  if (!tailorResponse && repeated429) {
    tailorResponse = await anthropic({
      model: 'claude-3-7-sonnet-20250219',
      max_tokens: 2600,
      temperature: 0.1,
      messages: [{ role: 'user', content: tailorPrompt }]
    }, { stage: 'tailor_fallback_429', userId });
  }

  const tailorText = tailorResponse && tailorResponse.content && tailorResponse.content[0] ? tailorResponse.content[0].text || '' : '';
  const tailored = parseJsonObject(tailorText);
  if (!tailored || typeof tailored !== 'object') {
    throw new Error('TAILORING_PARSE_FAILURE');
  }

  const idempotencyKey = 'tailor_v3:' + userId + ':' + jobId;
  await appWebhook(
    'single_tailoring_complete',
    {
      userId,
      jobId,
      jobTitle: jobTitle || 'Untitled Position',
      company: company || 'Unknown Company',
      compatibilityScore: Number(score.compatibility_score || 0),
      atsKeywords,
      matchingStrengths: Array.isArray(score.matching_strengths) ? score.matching_strengths.slice(0, 6) : [],
      gaps: Array.isArray(score.gaps) ? score.gaps.slice(0, 6) : [],
      recommendation: String(score.recommendation || 'stretch'),
      tailoredCvMarkdown: String(tailored.tailored_cv_markdown || ''),
      coverLetterMarkdown: String(tailored.motivation_letter_markdown || '')
    },
    { 'x-idempotency-key': idempotencyKey },
    { stage: 'persist_single_tailor', userId }
  );

  return [{ json: { ok: true, status: 200, runId, userId, jobId, idempotencyKey, persisted: true } }];
} catch (error) {
  const reasonCode = String(error && error.message ? error.message : 'SINGLE_TAILOR_V3_FAILED');
  await emitWorkflowError('single_tailor_pipeline', reasonCode, { runId, userId, jobId, reasonCode }, userId);
  return [{ json: { ok: false, status: 500, error: 'single_tailor_failed', reasonCode, runId, userId, jobId } }];
}
})();
